import React from 'react';
import RingIcon from '../assets/icons/RingIcon';
import DrinkIcon from '../assets/icons/DrinkIcon';
import FoodIcon from '../assets/icons/FoodIcon';

function Chronology() {
  return (
    <div className="w-full bg-white m-auto flex flex items-center justify-center gap-10 py-28">
      <div>
        <div className="text-3xl font-semibold text-[#656c64]">
          <RingIcon />
          <h2>20:30</h2>
        </div>
      </div>
      <div>
        <div>
          <DrinkIcon />
          <h2 className="text-3xl font-semibold text-[#656c64]">21:30</h2>
        </div>
      </div>

      <div>
        <div>
          <FoodIcon />
          <h2 className="text-3xl font-semibold text-[#656c64]">21:45</h2>
        </div>
      </div>
    </div>
  );
}

export default Chronology;
